#include <iostream>
#include <memory>
#include <string>

class Resource {
public:
  std::string data;
  Resource(const std::string& d) : data(d) { std::cout << "Constructor: " << data << "\n"; }
  ~Resource() { std::cout << "Destructor: " << data << "\n"; }
};

int main() {
  std::unique_ptr<Resource> ptr = std::make_unique<Resource>("Test");
  std::cout << "Data: " << ptr->data << "\n";
  return 0;
}
// Output:
// Constructor: Test
// Data: Test
// Destructor: Test

#include <iostream>
#include <memory>
#include <string>

class Resource {
public:
  std::string data;
  Resource(const std::string& d) : data(d) { std::cout << "Constructor: " << data << "\n"; }
  ~Resource() { std::cout << "Destructor: " << data << "\n"; }
};

int main() {
  std::shared_ptr<Resource> ptr1 = std::make_shared<Resource>("Shared");
  {
    std::shared_ptr<Resource> ptr2 = ptr1;
    std::cout << "ptr1 data: " << ptr1->data << "\n";
    std::cout << "ptr2 data: " << ptr2->data << "\n";
    std::cout << "Reference count: " << ptr1.use_count() << "\n";
  }
  std::cout << "After scope, ptr1 data: " << ptr1->data << "\n";
  return 0;
}
// Output:
// Constructor: Shared
// ptr1 data: Shared
// ptr2 data: Shared
// Reference count: 2
// After scope, ptr1 data: Shared
// Destructor: Shared

#include <iostream>
#include <memory>
#include <string>

class Resource {
public:
  std::string data;
  Resource(const std::string& d) : data(d) { std::cout << "Constructor: " << data << "\n"; }
  ~Resource() { std::cout << "Destructor: " << data << "\n"; }
};

int main() {
  std::weak_ptr<Resource> weak;
  {
    std::shared_ptr<Resource> shared = std::make_shared<Resource>("WeakTest");
    weak = shared;
    if (auto temp = weak.lock()) {
      std::cout << "Weak ptr data: " << temp->data << "\n";
    }
  }
  std::cout << "Expired: " << (weak.expired() ? "Yes" : "No") << "\n";
  return 0;
}
// Output:
// Constructor: WeakTest
// Weak ptr data: WeakTest
// Destructor: WeakTest
// Expired: Yes

